const puppeteer = require('puppeteer');
(async () => {
  // Launch the specific Chrome binary; keep the window visible
  const browser = await puppeteer.launch({
    headless: false,
    executablePath: 'C:\\Program Files\\Google\\Chrome\\Application\\chrome.exe',
    defaultViewport: null,
  });

  // Open two separate tabs with well‑known pages
  const pageA = await browser.newPage();
  await pageA.goto('https://example.com', { waitUntil: 'load' });

  const pageB = await browser.newPage();
  await pageB.goto('https://openai.com', { waitUntil: 'load' });

  // Give the pages a moment to settle so their title information is ready
  await new Promise(r => setTimeout(r, 2000));

  // Pull the list of *all* pages (tabs) that exist in this browser instance
  const pages = await browser.pages();

  console.log('\n=== Open Chrome tabs in this Chromium instance ===');
  pages.forEach((p, i) => {
    const title = p.title() || '(title not available)';
    console.log(`${i + 1}. ${title}`);
    console.log(`   → ${p.url()}`);
  });

  // Close the browser (the window will close, but the script already printed the tab list)
  await browser.close();
})();

