const puppeteer = require('puppeteer');

(async () => {
  // 1️⃣ launch the system Chrome binary, keep UI visible
  const browser = await puppeteer.launch({
    headless: false,
    executablePath: 'C:\\Program Files\\Google\\Chrome\\Application\\chrome.exe',
    defaultViewport: null,
  });

  // 2️⃣ open two obvious tabs – they’ll appear in the Chrome window you can watch
  const pageA = await browser.newPage();
  await pageA.goto('https://example.com', { waitUntil: 'load' });

  const pageB = await browser.newPage();
  await pageB.goto('https://openai.com', { waitUntil: 'load' });

  // Give the tabs a moment to settle and resolve titles
  await new Promise(r => setTimeout(r, 2500));

  // 3️⃣ collect **all** pages (tabs) that belong to this browser instance
  const pages = await browser.pages();

  console.log('\n=== Open Chrome tabs in this Chromium instance ===');
  for (let i = 0; i < pages.length; i++) {
    const page = pages[i];
    const title = await page.title(); // promise, await it
    const url = page.url();
    console.log(`${i + 1}. ${title}`);
    console.log(`   → ${url}`);
  }

  // 4️⃣ clean up – close the browser window (the script already printed the result)
  await browser.close();
})();

